def gen(rng, size):
    def make():
        n = rng.randint(0, max(0, min(size, 1000)))
        if n == 0:
            return []
        arr = [rng.randint(-10000, 10000)]
        for _ in range(n - 1):
            arr.append(rng.randint(-10000, 10000) if rng.random() < 0.7 else None)
        while arr and arr[-1] is None:
            arr.pop()
        return arr
    return [make(), make()]

